import { SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
import { conflictKeysForGrid, createGame, createSudoku } from '../../../domain/index.js';

/*
 * Store 适配层（作业里推荐的方案 A）。
 * 组件只管 subscribe、调 userGrid.set / undo / redo；底下真正改棋的是 domain里的 Game。
 * Svelte 3 只吃「引用有没有换」，所以每次领域动完，都要 getGrid() 再 set 进 writable。
 */

function emptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

function cloneGrid(g) {
	return g.map((row) => row.slice());
}

/** @type {ReturnType<typeof createGame> | null} */
let domainGame = null;

function createGrid() {
	const gridStore = writable(emptyGrid());

	return {
		subscribe: gridStore.subscribe,

		generate(difficulty) {
			gridStore.set(generateSudoku(difficulty));
		},

		decodeSencode(sencode) {
			gridStore.set(decodeSencode(sencode));
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();

const userGridWritable = writable(emptyGrid());

export const canUndo = writable(false);
export const canRedo = writable(false);

grid.subscribe(($grid) => {
	domainGame = createGame({ sudoku: createSudoku(cloneGrid($grid)) });
	syncUserGridFromDomain();
});

/** 把领域里的当前盘抄到 store，顺带刷新撤销/重做的按钮状态 */
function syncUserGridFromDomain() {
	if (!domainGame) return;
	userGridWritable.set(domainGame.getSudoku().getGrid());
	canUndo.set(domainGame.canUndo());
	canRedo.set(domainGame.canRedo());
}

function withDomainSync(run) {
	if (!domainGame) return;
	run();
	syncUserGridFromDomain();
}

function createUserGrid() {
	return {
		subscribe: userGridWritable.subscribe,

		set(pos, value) {
			withDomainSync(() => {
				domainGame.guess({ row: pos.y, col: pos.x, value });
			});
		},

		applyHint(pos) {
			withDomainSync(() => {
				hints.useHint();
				const g = domainGame.getSudoku().getGrid();
				const solvedSudoku = solveSudoku(g);
				domainGame.guess({ row: pos.y, col: pos.x, value: solvedSudoku[pos.y][pos.x] });
			});
		},

		undo() {
			withDomainSync(() => {
				domainGame.undo();
			});
		},

		redo() {
			withDomainSync(() => {
				domainGame.redo();
			});
		},

		canUndo() {
			return domainGame ? domainGame.canUndo() : false;
		},

		canRedo() {
			return domainGame ? domainGame.canRedo() : false;
		},
	};
}

export const userGrid = createUserGrid();

export const invalidCells = derived(userGridWritable, ($userGrid) => conflictKeysForGrid($userGrid), []);

export function createGameStore() {
	return { grid, userGrid, invalidCells };
}
